class MedianFinder {
    // maxHeap: lower half (max at top)
    private PriorityQueue<Integer> lower = new PriorityQueue<>(Collections.reverseOrder());
    // minHeap: upper half (min at top)
    private PriorityQueue<Integer> upper = new PriorityQueue<>();

    public void addNum(int num) {
        lower.offer(num);
        upper.offer(lower.poll()); // ensure upper's min >= lower's max
        if (lower.size() < upper.size()) lower.offer(upper.poll()); // rebalance
    }

    public double findMedian() {
        return lower.size() > upper.size()
            ? lower.peek()
            : (lower.peek() + upper.peek()) / 2.0;
    }
}

