public class Solution {
    public int findMaximizedCapital(int k, int w, int[] profits, int[] capital) {
        int n = profits.length;
        int[][] projects = new int[n][2];
        for (int i = 0; i < n; i++) projects[i] = new int[]{capital[i], profits[i]};
        Arrays.sort(projects, Comparator.comparingInt(a -> a[0])); // sort by capital

        PriorityQueue<Integer> maxProfit = new PriorityQueue<>(Collections.reverseOrder());
        int idx = 0;
        for (int i = 0; i < k; i++) {
            // Unlock all affordable projects
            while (idx < n && projects[idx][0] <= w) maxProfit.offer(projects[idx++][1]);
            if (maxProfit.isEmpty()) break; // no affordable project
            w += maxProfit.poll();
        }
        return w;
    }
}

